#include <stdio.h>
#include <stdlib.h>
#define MAXN 500

int directions[][2] = {{0, 1}, {0, -1}, {1, 0}, {-1, 0}};

int dfs(int **grid, int n, int x, int y, int **visited) {
    if (x < 0 || x >= n || y < 0 || y >= n || grid[x][y] == 0 || visited[x][y]) return 0;
    visited[x][y] = 1;
    int size = 1;
    for (int i = 0; i < 4; i++) {
        size += dfs(grid, n, x + directions[i][0], y + directions[i][1], visited);
    }
    return size;
}

int findLargestIsland(int **grid, int n) {
    int max_size = 0;
    int **visited = (int **)malloc(n * sizeof(int *));
    for (int i = 0; i < n; i++) {
        visited[i] = (int *)malloc(n * sizeof(int));
    }
    for (int i = 0; i < n; i++) {
        for (int j = 0; j < n; j++) {
            if (grid[i][j] == 1 && !visited[i][j]) {
                int size = dfs(grid, n, i, j, visited);
                max_size = (size > max_size) ? size : max_size;
            }
        }
    }
    for (int i = 0; i < n; i++) {
        free(visited[i]);
    }
    free(visited);
    return max_size;
}

int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        int n;
        scanf("%d", &n);
        int **grid = (int **)malloc(n * sizeof(int *));
        for (int i = 0; i < n; i++) {
            grid[i] = (int *)malloc(n * sizeof(int));
        }
        for (int i = 0; i < n; i++) {
            for (int j = 0; j < n; j++) {
                scanf("%d", &grid[i][j]);
            }
        }
        int max_size = findLargestIsland(grid, n);
        for (int i = 0; i < n; i++) {
            for (int j = 0; j < n; j++) {
                if (grid[i][j] == 0) {
                    grid[i][j] = 1;
                    max_size = (findLargestIsland(grid, n) > max_size) ? findLargestIsland(grid, n) : max_size;
                    grid[i][j] = 0;
                }
            }
        }
        printf("%d\n", max_size);
        for (int i = 0; i < n; i++) {
            free(grid[i]);
        }
        free(grid);
    }
    return 0;
}

