        while (T-- > 0) {
            int n = scanner.nextInt();
            int[][] grid = new int[n][n];
            for (int i = 0; i < n; i++) {
                for (int j = 0; j < n; j++) {
                    grid[i][j] = scanner.nextInt();
                }
            }
            int max_size = findLargestIsland(grid, n);
            for (int i = 0; i < n; i++) {
                for (int j = 0; j < n; j++) {
                    if (grid[i][j] == 0) {
                        grid[i][j] = 1;
                        max_size = Math.max(findLargestIsland(grid, n), max_size);
                        grid[i][j] = 0;
                    }
                }
            }
            System.out.println(max_size);
        }
    }
    public static int findLargestIsland(int[][] grid, int n) {
        int max_size = 0;
        int[][] visited = new int[n][n];
        for (int i = 0; i < n; i++) {
            for (int j = 0; j < n; j++) {
                if (grid[i][j] == 1 && visited[i][j] == 0) {
                    int size = dfs(grid, n, i, j, visited);
                    max_size = Math.max(size, max_size);
                }
            }
        }
        return max_size;
    }
    public static int dfs(int[][] grid, int n, int x, int y, int[][] visited) {
        if (x < 0 || x >= n || y < 0 || y >= n || grid[x][y] == 0 || visited[x][y] == 1) return 0;
        visited[x][y] = 1;
        int size = 1;
        for (int i = 0; i < 4; i++) {
            size += dfs(grid, n, x + directions[i][0], y + directions[i][1], visited);
        }
        return size;
    }
