import sys
input = sys.stdin.readline

directions = [[0, 1], [0, -1], [1, 0], [-1, 0]]

def dfs(grid, n, x, y, visited):
    if x < 0 or x >= n or y < 0 or y >= n or grid[x][y] == 0 or visited[x][y]: return 0
    visited[x][y] = 1
    size = 1
    for i in range(4):
        size += dfs(grid, n, x + directions[i][0], y + directions[i][1], visited)
    return size

def findLargestIsland(grid, n):
    max_size = 0
    visited = [[0]*n for _ in range(n)]
    for i in range(n):
        for j in range(n):
            if grid[i][j] == 1 and not visited[i][j]:
                size = dfs(grid, n, i, j, visited)
                max_size = max(size, max_size)
    return max_size

def main():
    T = int(input())
    for _ in range(T):
        n = int(input())
        grid = [list(map(int, input().split())) for _ in range(n)]
        max_size = findLargestIsland(grid, n)
        for i in range(n):
            for j in range(n):
                if grid[i][j] == 0:
                    grid[i][j] = 1
                    max_size = max(findLargestIsland(grid, n), max_size)
                    grid[i][j] = 0
        print(max_size)
if __name__ == '__main__':
    main()

