const directions = [[0, 1], [0, -1], [1, 0], [-1, 0]];

function dfs(grid, n, x, y, visited) {
    if (x < 0 || x >= n || y < 0 || y >= n || grid[x][y] === 0 || visited[x][y]) return 0;
    visited[x][y] = 1;
    let size = 1;
    for (let i = 0; i < 4; i++) {
        size += dfs(grid, n, x + directions[i][0], y + directions[i][1], visited);
    }
    return size;
}

function findLargestIsland(grid, n) {
    let max_size = 0;
    let visited = Array(n).fill(0).map(() => Array(n).fill(0));
    for (let i = 0; i < n; i++) {
        for (let j = 0; j < n; j++) {
            if (grid[i][j] === 1 && !visited[i][j]) {
                let size = dfs(grid, n, i, j, visited);
                max_size = Math.max(size, max_size);
            }
        }
    }
    return max_size;
}

